const { agent_email, address } = $input.first().json.body;
if (!agent_email || !address) throw new Error('Missing agent_email or address');
const chars = 'abcdefghijklmnopqrstuvwxyz0123456789';
const rand6 = Array.from({length:6}, () => chars[Math.floor(Math.random()*chars.length)]).join('');
const slug = address.toLowerCase().replace(/[^a-z0-9]+/g,'-').replace(/^-|-$/g,'').substring(0,50) + '-' + rand6;
return [{ json: { slug, agent_email, address } }];

const AWS = require('aws-sdk');

const slug = $('Generate Slug').first().json.slug;
const r2VideoPath = `uploads/${slug}/video.mp4`;

const s3 = new AWS.S3({
  endpoint: `https://${$env.CF_ACCOUNT_ID}.r2.cloudflarestorage.com`,
  accessKeyId: $env.R2_ACCESS_KEY_ID,
  secretAccessKey: $env.R2_SECRET_ACCESS_KEY,
  region: 'auto',
  signatureVersion: 'v4',
  s3ForcePathStyle: true,
});

const uploadUrl = await s3.getSignedUrlPromise('putObject', {
  Bucket: $env.R2_BUCKET,
  Key: r2VideoPath,
  Expires: 3600,
  ContentType: 'video/mp4',
});

return [{ json: {
  ok: true,
  slug,
  upload_url: uploadUrl,
  r2_video_path: r2VideoPath,
  airtable_record_id: $('Create Airtable Job').first().json.id
}}];
